//----------------------Function to Build the dialog of Depth Analysis command STARTS------------------------//
void MRFDepthAnsysCmdDlg::Build()
{
	_pMainFrame = new CATDlgFrame(this, (const char*)"MainFrame", 0 | CATDlgGridLayout | CATDlgFraNoTitle | CATDlgFraNoFrame);
	_pMainFrame->SetGridConstraints(0, 0, 3, 7, CATGRID_4SIDES);

	_lblSourceSurafce = new CATDlgLabel(_pMainFrame, (const char*)"Source Surface ", CATDlgLabLeft);
	_lblSourceSurafce->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	_selectorListSourceSurf = new CATDlgSelectorList(_pMainFrame, (const char*)"Source Surface SelList", CATDlgLabCenter | CATDlgLabRight);
	_selectorListSourceSurf->SetGridConstraints(0, 1, 2, 1, CATGRID_4SIDES);
	_selectorListSourceSurf->SetVisibleTextHeight(1);
	_selectorListSourceSurf->SetVisibleTextWidth(20);
	_selectorListSourceSurf->SetLine("No Selection");

	_contextMenuClearSelectionSourceSurf = new CATDlgContextualMenu(_selectorListSourceSurf, (const char*)"Clear SourceSurface", CATDlgCtxEmpty);

	_lblBaldSurface = new CATDlgLabel(_pMainFrame, (const char*)"Reference Surface", CATDlgLabLeft | CATDlgLabRight | CATDlgLabCenter);
	_lblBaldSurface->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

	_selectorListBaldSurf = new CATDlgSelectorList(_pMainFrame, (const char*)"Source Surface SelList", CATDlgLabCenter | CATDlgLabRight);
	_selectorListBaldSurf->SetGridConstraints(1, 1, 2, 1, CATGRID_4SIDES);
	_selectorListBaldSurf->SetVisibleTextHeight(1);
	_selectorListBaldSurf->SetVisibleTextWidth(20);
	_selectorListBaldSurf->SetLine("No Selection");

	_contextMenuClearSelectionBaldSurf = new CATDlgContextualMenu(_selectorListBaldSurf, (const char*)"Clear BaldSurface", CATDlgCtxEmpty);

	_lblGridSpacingLateralDir = new CATDlgLabel(_pMainFrame, (const char*)"Lateral Spacing (mm)", CATDlgLabLeft | CATDlgLabRight | CATDlgLabCenter);
	_lblGridSpacingLateralDir->SetGridConstraints(3, 0, 1, 1, CATGRID_4SIDES);

	_editDoubleGridSpacingLateral = new CATDlgSpinner(_pMainFrame, (const char*)"Grid Spacing Lateral", CATDlgSpnDouble| CATDlgSpnEntry);
	_editDoubleGridSpacingLateral->SetGridConstraints(3, 1, 1, 1, CATGRID_4SIDES);
	_editDoubleGridSpacingLateral->SetMinMaxStep(0.1, 10000000, 0.1);
	_editDoubleGridSpacingLateral->SetValue(lateralSpinnerValue);

	_lblGridSpacingCircumDir = new CATDlgLabel(_pMainFrame, (const char*)"Circumferential Grid Count", CATDlgLabLeft | CATDlgLabRight | CATDlgLabCenter);
	_lblGridSpacingCircumDir->SetGridConstraints(4, 0, 1, 1, CATGRID_4SIDES);

	_editDoubleGridSpacingCircumf = new CATDlgSpinner(_pMainFrame, (const char*)"Grid Spacing Circumf", CATDlgSpnDouble| CATDlgSpnEntry);
	_editDoubleGridSpacingCircumf->SetGridConstraints(4, 1, 1, 1, CATGRID_4SIDES);
	_editDoubleGridSpacingCircumf->SetMinMaxStep(1., 1e9, 1);
	_editDoubleGridSpacingCircumf->SetValue(cirmuferenceSpinnerValue);

	_checkButtonTyreDirection = new CATDlgCheckButton(_pMainFrame, (const char*)"Is Directional Tyre", 0);
	_checkButtonTyreDirection->SetGridConstraints(5, 0, 1, 1, CATGRID_4SIDES);

	_pushButtonReverseDirection = new CATDlgPushButton(_pMainFrame, "Reverse Direction", CATDlgPusRepetitive || CATDlgPusNoShadow);
	_pushButtonReverseDirection->SetIconName("I_OffsetReverseDirection");
	_pushButtonReverseDirection->SetGridConstraints(5, 1, 1, 1, CATGRID_4SIDES);
	_pushButtonReverseDirection->SetSensitivity(CATDlgDisable);

	_checkButtonPreview = new CATDlgCheckButton(_pMainFrame, (const char*)"Preview Points", 0);
	_checkButtonPreview->SetGridConstraints(5, 2, 1, 1, CATGRID_4SIDES);

	_pDlgProgress = new CATDlgProgress(_pMainFrame, "Progress");
	_pDlgProgress->SetGridConstraints(6, 0, 3, 1, 0);
	_pDlgProgress->SetVisibility(CATDlgHide);	

	this->SetCANCELTitle((const char*)"Close");
	this->SetOKTitle((const char*)"  Generate Report  ");


}
//----------------------Function to Build the dialog of Depth Analysis command ENDS------------------------//

//------------------------Function to be called when Inverse Tyre Direction PushButton is Clicked STARTS----------------//
void MRFDepthAnsysCmdDlg::OnCheckButtonTyreDirectionChanged()
{
	if (_checkButtonTyreDirection->GetState() == CATDlgCheck)
	{
		_pushButtonReverseDirection->SetSensitivity(CATDlgEnable);
	}
	else
	{
		_pushButtonReverseDirection->SetSensitivity(CATDlgDisable);
	}
}
//------------------------Function to be called when Inverse Tyre Direction PushButton is Clicked ENDS----------------//

//--------------------Functionn to set focus on selector list STARTS-------------------//
void MRFDepthAnsysCmdDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);
	}
}
//--------------------Functionn to set focus on selector list ENDS-------------------//

//---------------------Function to set the given name to the  Selector List Source surface STARTS------------------------// 
void MRFDepthAnsysCmdDlg::SetSelectorListSourceSurf(const CATUnicodeString ipSourceSurf)
{
	_selectorListSourceSurf->ClearLine();
	_selectorListSourceSurf->SetLine(ipSourceSurf);

}
//---------------------Function to set the given name to the  Selector List Source surface ENDS------------------------// 

//---------------------Function to set the given name to the  Selector List Bald surface STARTS------------------------// 
void MRFDepthAnsysCmdDlg::SetSelectorListBaldSurf(const CATUnicodeString ipBaldSurf)
{
	_selectorListBaldSurf->ClearLine();
	_selectorListBaldSurf->SetLine(ipBaldSurf);

}
